svg.script:

(function () {
  function dataFor(zone) {
    return {
      id: zone.id,
      part: zone.dataset.part,
      view: zone.dataset.view,
      side: zone.dataset.side,
      label: zone.dataset.label
    };
  }
  function activate(zone) {
    if (!zone || !zone.classList || !zone.classList.contains('hit')) return;
    document.querySelectorAll('.hit.active').forEach(function (el) { el.classList.remove('active'); });
    zone.classList.add('active');
    var event = new CustomEvent('bodypartclick', { detail: dataFor(zone), bubbles: true });
    zone.dispatchEvent(event);
    if (window.parent && window.parent !== window) {
      window.parent.postMessage({ type: 'bodypartclick', detail: dataFor(zone) }, '*');
    }
  }
  document.addEventListener('click', function (e) {
    var zone = e.target.closest && e.target.closest('.hit');
    activate(zone);
  });
  document.addEventListener('keydown', function (e) {
    if (e.key !== 'Enter' && e.key !== ' ') return;
    var zone = e.target.closest && e.target.closest('.hit');
    if (zone) { e.preventDefault(); activate(zone); }
  });
}());
